/**
 * @typedef {Object} DiffResult
 * @property {Array<DiffChange>} changes - Array of diff changes
 * @property {string} summary - Summary of changes
 * @property {boolean} identical - Whether the PDFs are identical
 */

/**
 * @typedef {Object} DiffChange
 * @property {boolean} [added] - Whether this change is an addition (undefined for unchanged text)
 * @property {boolean} [removed] - Whether this change is a removal (undefined for unchanged text)
 * @property {string} value - The text content of the change
 * @property {number} [count] - Number of units (characters/words/lines) in this change
 */

/**
 * @typedef {'char'|'word'|'line'} DiffMode
 */

/**
 * @typedef {Object} CompareOptions
 * @property {boolean} [ignoreWhitespace=false] - Whether to ignore whitespace differences
 * @property {boolean} [ignoreCase=false] - Whether to ignore case differences
 * @property {DiffMode} [mode='char'] - Diff mode: character, word, or line level
 */

/**
 * @typedef {Object} TextProcessingOptions
 * @property {boolean} [ignoreCase=false] - Whether to ignore case differences
 * @property {boolean} [ignoreWhitespace=false] - Whether to ignore whitespace differences
 */

/**
 * @typedef {Object} FormatOptions
 * @property {boolean} [showUnchanged=false] - Show unchanged lines in output
 * @property {number} [context=3] - Number of context lines around changes
 * @property {boolean} [color=true] - Enable color output
 */

/**
 * @typedef {CompareOptions & {pdfjsLib?: import('./utils/pdfjs-extractor.js').PDFJSLib}} BrowserCompareOptions
 */

/**
 * @typedef {'added'|'removed'|'unchanged'} VisualDiffType
 */

/**
 * @typedef {Object} VisualDiffItem
 * @property {string} text - Text content
 * @property {number} x - X coordinate
 * @property {number} y - Y coordinate
 * @property {number} width - Text width
 * @property {number} height - Text height
 * @property {number} page - Page number
 * @property {VisualDiffType} type - Type of change
 * @property {string} [fontName] - Font name
 * @property {Array<number>} transform - Transformation matrix
 */

/**
 * @typedef {Object} VisualDiffSummary
 * @property {number} addedCount - Number of added text items
 * @property {number} removedCount - Number of removed text items
 * @property {number} unchangedCount - Number of unchanged text items
 */

/**
 * @typedef {Object} VisualDiffPageInfo
 * @property {number} maxPages - Maximum pages across both PDFs
 */

/**
 * @typedef {Object} VisualDiffResult
 * @property {Array<VisualDiffItem>} items - Visual diff items with positions
 * @property {VisualDiffSummary} summary - Summary of visual changes
 * @property {boolean} identical - Whether PDFs are visually identical
 * @property {VisualDiffPageInfo} pageInfo - Information about pages
 */

export {};